    "code": "import json
import os

# Load children's books data
with open('var_functions.query_db_34', 'r') as f:
    children_books_data = json.load(f)

# Create mapping from purchase_id to title
children_books = {}
for book in children_books_data:
    purchase_id = book['book_id'].replace('bookid_', 'purchaseid_')
    children_books[purchase_id] = book['title']

# Load reviews from 2020 onwards
with open('var_functions.query_db_38', 'r') as f:
    all_reviews = json.load(f)

# Filter reviews for children's books and calculate ratings
children_reviews = []
for review in all_reviews:
    purchase_id = review['purchase_id']
    if purchase_id in children_books:
        children_reviews.append({
            'purchase_id': purchase_id,
            'title': children_books[purchase_id],
            'rating': float(review['rating'])
        })

print(f"Total reviews from 2020 onwards: {len(all_reviews)}")
print(f"Children's book reviews from 2020 onwards: {len(children_reviews)}")
print(f"Number of children's books with reviews: {len(set(r['purchase_id'] for r in children_reviews))}")

# Group by book and calculate average rating
from collections import defaultdict
book_ratings = defaultdict(list)
for review in children_reviews:
    book_ratings[review['title']].append(review['rating'])

# Calculate average ratings
avg_ratings = {}
for title, ratings in book_ratings.items():
    avg = sum(ratings) / len(ratings)
    avg_ratings[title] = {
        'average_rating': avg,
        'review_count': len(ratings)
    }

# Filter books with average rating >= 4.5
high_rated_books = {title: info for title, info in avg_ratings.items() 
                    if info['average_rating'] >= 4.5}

print(f"Books with avg rating >= 4.5: {len(high_rated_books)}")

# Sort by rating (descending)
sorted_books = sorted(high_rated_books.items(), 
                      key=lambda x: x[1]['average_rating'], 
                      reverse=True)

# Prepare result
result = []
for title, info in sorted_books:
    result.append({
        'title': title,
        'average_rating': round(info['average_rating'], 2),
        'review_count': info['review_count']
    })

# Print results in required format
print('__RESULT__:')
print(json.dumps(result, indent=2))"
